+  const occupied = std > 0.01; // empirical threshold for the demo
+  const wasOccupied = (ctx.state['occ'] ?? 0) > 0.5;
+  if (occupied !== wasOccupied) {
+    ctx.state['occ'] = occupied ? 1 : 0;
+    ctx.state['lastEmitS'] = ctx.elapsedS;
