+      ts: Date.now(),
+      appId: 'occupancy',
+      eventId: occupied ? 300 : 302,
+      eventName: occupied ? 'ZONE_OCCUPIED' : 'ZONE_TRANSITION',
+      value: std,
+      detail: occupied ? `σ(|B|)=${std.toFixed(3)} nT — entered` : `σ(|B|)=${std.toFixed(3)} nT — left`,
+    };
+  }
+  return null;
+};
