+const exoGhostHunter: AppRuntimeFn = (ctx) => {
+  if (ctx.bHistory.length < 128) return null;
+  const last = ctx.state['lastEmitS'] ?? 0;
+  if (ctx.elapsedS - last < 4.0) return null;
+  ctx.state['lastEmitS'] = ctx.elapsedS;
