+    t2_star_s?: number;
+    contrast?: number;
+    n_spins?: number;
+    n_centers?: number;
+    shot_noise_disabled?: boolean;
+  };
+  dt_s?: number | null;
+}
+
+export interface SceneJson {
+  dipoles: { position: [number, number, number]; moment: [number, number, number] }[];
+  loops: {
+    centre: [number, number, number];
+    normal: [number, number, number];
+    radius: number;
+    current: number;
+    n_segments: number;
+  }[];
+  ferrous: {
