+  }
+
+  onFrames(cb: (batch: MagFrameBatch) => void): void { this.frameSubs.add(cb); }
+  onEvent(cb: (ev: NvsimEvent) => void): void { this.eventSubs.add(cb); }
+
+  async generateWitness(samples: number): Promise<Uint8Array> {
