+  }
+
+  async buildId(): Promise<string> {
+    const r = await this.rpc<{ buildId: string }>({ type: 'buildId' });
+    return r.buildId;
+  }
+
+  async close(): Promise<void> {
+    this.worker.terminate();
+  }
+}

