+        let f_c = 100.0;
+        let f_test = 5_000.0;
+        let mut lp = LowPass::new(f_c, f_s);
+        let n = 4096;
+        let mut peak = 0.0_f64;
+        for i in 0..n {
+            let t = i as f64 / f_s;
+            let x = (2.0 * std::f64::consts::PI * f_test * t).sin();
+            let y = lp.process(x);
+            if i > n / 2 {
