+        // already baked into Lockin::process).
+        let f_mod = 1_000.0;
+        let f_s = 10_000.0;
+        let mut lockin = Lockin::new(f_mod, f_s);
+        let n = (f_s as usize) * 2; // 2 s of samples for LP settling
+        let mut last = 0.0;
+        for i in 0..n {
+            let t = i as f64 / f_s;
+            let x = (2.0 * std::f64::consts::PI * f_mod * t).cos();
+            last = lockin.process(x);
+        }
